cd "$(cat /tmp/wsdir | cut -d= -f2)"; for q in 262505 698278 494140 757107 912807; do echo "=== $q ==="; grep -A 2 "^### $q " memory/q_detail.txt | head -3; for f in $(ls -t predictions/*.json); do python3 -c "
import json
d=json.load(open('$f'))
for e in d:
    if e['question_id']=='$q': print('  PRED:', e['outcomes'])
" 2>/dev/null; done | head -1; done
